class Solution {
public:
    vector<vector<int>> permuteMatrix(vector<vector<char>> matrix, vector<int> nums) {
        vector<vector<int>> result;
        int matrix_size_m = matrix.size(), matrix_size_n = matrix[0].size();
        int n = nums.size();
        bool backtrack(int x, int y, vector<int> &nums, vector<vector<int>> &matrix, unordered_set<int> &used) {
            if (x == matrix_size_m - 1) return true;
            for (int num : nums) {
                if (!used.count(num) && !used.count(matrix[x][y]) && !used.count(matrix[x - 1][y]) && !used.count(matrix[x][y - 1])) {
                    used.insert(num);
                    used.insert(matrix[x][y]);
                    used.insert(matrix[x - 1][y]);
                    used.insert(matrix[x][y - 1]);
                    if (backtrack(x + 1, y, nums, matrix, used)) return true;
                    used.erase(num);
                    used.erase(matrix[x][y]);
                    used.erase(matrix[x - 1][y]);
                    used.erase(matrix[x][y - 1]);
                }
            }
            return false;
        }
        if (!backtrack(0, 0, nums, matrix, {})) {
            return vector<vector<int>>();
        }
        return result;
    }
};
int main() {
    int matrix_size_m, matrix_size_n;
    scanf("%d %d", &matrix_size_m, &matrix_size_n);
    vector<vector<char>> matrix(matrix_size_m, vector<char>(matrix_size_n));
    for (int i = 0; i < matrix_size_m; i++) {
        for (int j = 0; j < matrix_size_n; j++) {
            scanf(" %c", &matrix[i][j]);
        }
    }
    int n;
    scanf("%d", &n);
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        scanf("%d", &nums[i]);
    }
    Solution solution;
    vector<vector<int>> result = solution.permuteMatrix(matrix, nums);
    if (result.empty()) {
        printf("None\n");
    } else {
        for (int i = 0; i < result.size(); i++) {
            for (int j = 0; j < result[i].size(); j++) {
                printf("%d", result[i][j]);
                if (j != result[i].size() - 1) printf(" ");
            }
            printf("\n");
        }
    }
    return 0;
}
